func Test_ErrorHandlingInvalidSyntax(t *testing.T) {
	// Parsing invalid syntax should produce a tree with error nodes.
	var config tspack.ProcessConfig
	if err := json.Unmarshal([]byte(`{"language":"javascript"}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	_, err := tspack.Process(`function function function @@@ %%%`, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
}

func Test_ErrorHandlingUnknownLanguage(t *testing.T) {
	// Loading a nonexistent language should produce an error.
	var config tspack.ProcessConfig
	if err := json.Unmarshal([]byte(`{"language":"nonexistent_xyz"}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	_, err := tspack.Process(``, config)
	if err == nil {
		t.Errorf("expected an error, but call succeeded")
	}
}

func Test_ErrorProcessEmptySource(t *testing.T) {
	// Process empty source code succeeds with zero metrics
	var config tspack.ProcessConfig
	if err := json.Unmarshal([]byte(`{"language":"python"}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := tspack.Process(``, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if result.Metrics.TotalLines != 0 {
		t.Errorf("equals mismatch: got %v", result.Metrics.TotalLines)
	}
}

func Test_ParseEmptyLanguage(t *testing.T) {
	// process() returns error with empty language name
	var config tspack.ProcessConfig
	if err := json.Unmarshal([]byte(`{"language":""}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	_, err := tspack.Process(`x = 1`, config)
	if err == nil {
		t.Errorf("expected an error, but call succeeded")
	}
}

func Test_ProcessUnknownLanguage(t *testing.T) {
	// process() returns error when config language is unknown
	var config tspack.ProcessConfig
	if err := json.Unmarshal([]byte(`{"language":"nonexistent_xyz"}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	_, err := tspack.Process(`x = 1`, config)
	if err == nil {
		t.Errorf("expected an error, but call succeeded")
	}
}
